import { useState, useEffect } from 'react';
import API from '../services/axios';

const T = "-apple-system, BlinkMacSystemFont, 'SF Pro Display', 'Segoe UI', sans-serif";
const GOLD = '#D4AF37';

function PaymentModal({ booking, onClose, onSuccess }) {
  const [tab, setTab] = useState('card');
  const [card, setCard] = useState({ number: '', name: '', expiry: '', cvv: '' });
  const [upi, setUpi] = useState('');
  const [bank, setBank] = useState('');
  const [flipped, setFlipped] = useState(false);
  const [processing, setProcessing] = useState(false);
  const [done, setDone] = useState(false);
  const [txnId] = useState('TXN' + Date.now());

  const amount = booking?.totalAmount || booking?.totalPrice || booking?.amount || 0;

  const inp = { width: '100%', padding: '12px 14px', background: '#111', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '9px', color: '#fff', fontSize: '0.88rem', fontFamily: T, outline: 'none', boxSizing: 'border-box' };

  const pay = async () => {
    setProcessing(true);
    await new Promise(r => setTimeout(r, 2000));
    try {
      await API.post('/payments', { booking: booking._id, amount, paymentMethod: tab, transactionId: txnId, status: 'success' });
      setDone(true);
    } catch { setDone(true); }
    finally { setProcessing(false); }
  };

  const BANKS = ['SBI', 'HDFC', 'ICICI', 'Axis', 'Kotak', 'PNB'];

  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.85)', zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '1rem', fontFamily: T }}>
      <style>{`@keyframes slideUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}} input::placeholder{color:#333}`}</style>
      <div style={{ background: '#0d0d0d', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '20px', width: '100%', maxWidth: '420px', overflow: 'hidden', animation: 'slideUp 0.3s ease' }}>

        {/* Header */}
        <div style={{ padding: '1.2rem 1.5rem', borderBottom: '1px solid rgba(255,255,255,0.06)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <p style={{ color: '#555', fontSize: '0.72rem', fontWeight: 700, letterSpacing: '0.8px', textTransform: 'uppercase', margin: '0 0 4px' }}>Secure Payment</p>
            <p style={{ color: GOLD, fontWeight: 700, fontSize: '1.3rem', margin: 0 }}>₹{amount.toLocaleString()}</p>
          </div>
          <button onClick={onClose} style={{ background: 'transparent', border: '1px solid rgba(255,255,255,0.1)', color: '#666', borderRadius: '8px', width: '32px', height: '32px', cursor: 'pointer', fontFamily: T, fontSize: '1rem' }}>✕</button>
        </div>

        {done ? (
          <div style={{ padding: '2.5rem', textAlign: 'center' }}>
            <div style={{ width: '56px', height: '56px', background: 'rgba(48,209,88,0.1)', border: '1px solid rgba(48,209,88,0.25)', borderRadius: '14px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.6rem', margin: '0 auto 1.2rem' }}>✓</div>
            <h3 style={{ color: '#fff', fontWeight: 700, margin: '0 0 8px' }}>Payment Successful</h3>
            <p style={{ color: '#555', fontSize: '0.84rem', margin: '0 0 6px' }}>Transaction ID</p>
            <p style={{ color: GOLD, fontWeight: 700, fontSize: '0.9rem', margin: '0 0 1.5rem', letterSpacing: '0.5px' }}>{txnId}</p>
            <button onClick={() => { onSuccess(); onClose(); }} style={{ width: '100%', padding: '13px', background: GOLD, color: '#000', border: 'none', borderRadius: '10px', fontWeight: 700, cursor: 'pointer', fontFamily: T }}>Done</button>
          </div>
        ) : processing ? (
          <div style={{ padding: '3rem', textAlign: 'center' }}>
            <div style={{ width: '40px', height: '40px', border: '2px solid #222', borderTopColor: GOLD, borderRadius: '50%', animation: 'spin 0.8s linear infinite', margin: '0 auto 1rem' }} />
            <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
            <p style={{ color: '#A0A0A0' }}>Processing payment...</p>
          </div>
        ) : (
          <div style={{ padding: '1.5rem' }}>
            {/* Tabs */}
            <div style={{ display: 'flex', gap: '6px', marginBottom: '1.5rem', background: '#111', borderRadius: '10px', padding: '4px' }}>
              {['card', 'upi', 'netbanking'].map(t => (
                <button key={t} onClick={() => setTab(t)} style={{ flex: 1, padding: '8px', borderRadius: '7px', border: 'none', cursor: 'pointer', fontWeight: 700, fontSize: '0.78rem', fontFamily: T, textTransform: 'capitalize', background: tab === t ? GOLD : 'transparent', color: tab === t ? '#000' : '#555', transition: 'all 0.2s' }}>
                  {t === 'netbanking' ? 'Net Banking' : t.toUpperCase()}
                </button>
              ))}
            </div>

            {/* Card */}
            {tab === 'card' && (
              <div>
                <div onClick={() => setFlipped(f => !f)} style={{ height: '120px', background: 'linear-gradient(135deg, #1a1500, #111)', border: `1px solid rgba(212,175,55,0.2)`, borderRadius: '14px', padding: '1.2rem', marginBottom: '1.2rem', cursor: 'pointer', position: 'relative', overflow: 'hidden' }}>
                  <div style={{ position: 'absolute', top: '12px', right: '14px', color: GOLD, fontWeight: 700, fontSize: '0.8rem', opacity: 0.6 }}>VISA</div>
                  {!flipped ? (
                    <>
                      <p style={{ color: '#555', fontSize: '0.65rem', margin: '0 0 6px', letterSpacing: '1px', textTransform: 'uppercase' }}>Card Number</p>
                      <p style={{ color: '#fff', fontWeight: 700, fontSize: '1rem', letterSpacing: '3px', margin: '0 0 12px' }}>{card.number || '•••• •••• •••• ••••'}</p>
                      <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                        <p style={{ color: '#A0A0A0', fontSize: '0.8rem', margin: 0 }}>{card.name || 'CARD HOLDER'}</p>
                        <p style={{ color: '#A0A0A0', fontSize: '0.8rem', margin: 0 }}>{card.expiry || 'MM/YY'}</p>
                      </div>
                    </>
                  ) : (
                    <div style={{ paddingTop: '24px', textAlign: 'center' }}>
                      <p style={{ color: '#555', fontSize: '0.65rem', letterSpacing: '1px', textTransform: 'uppercase', margin: '0 0 6px' }}>CVV</p>
                      <p style={{ color: '#fff', fontWeight: 700, fontSize: '1.2rem', letterSpacing: '4px' }}>{card.cvv || '•••'}</p>
                    </div>
                  )}
                </div>
                {[
                  { label: 'Card Number', key: 'number', placeholder: '1234 5678 9012 3456', maxLength: 19 },
                  { label: 'Cardholder Name', key: 'name', placeholder: 'As on card' },
                  { label: 'Expiry (MM/YY)', key: 'expiry', placeholder: 'MM/YY', maxLength: 5 },
                ].map(f => (
                  <div key={f.key} style={{ marginBottom: '10px' }}>
                    <label style={{ display: 'block', color: '#555', fontSize: '0.72rem', fontWeight: 700, letterSpacing: '0.5px', textTransform: 'uppercase', marginBottom: '5px' }}>{f.label}</label>
                    <input value={card[f.key]} onChange={e => setCard(c => ({ ...c, [f.key]: e.target.value }))} placeholder={f.placeholder} maxLength={f.maxLength} style={inp}
                      onFocus={e => { e.target.style.borderColor = GOLD; if (f.key === 'cvv') setFlipped(true); }}
                      onBlur={e => { e.target.style.borderColor = 'rgba(255,255,255,0.1)'; if (f.key === 'cvv') setFlipped(false); }} />
                  </div>
                ))}
                <div style={{ marginBottom: '1.2rem' }}>
                  <label style={{ display: 'block', color: '#555', fontSize: '0.72rem', fontWeight: 700, letterSpacing: '0.5px', textTransform: 'uppercase', marginBottom: '5px' }}>CVV</label>
                  <input value={card.cvv} onChange={e => setCard(c => ({ ...c, cvv: e.target.value }))} placeholder="•••" maxLength={4} type="password" style={{ ...inp, width: '100px' }}
                    onFocus={e => { e.target.style.borderColor = GOLD; setFlipped(true); }}
                    onBlur={e => { e.target.style.borderColor = 'rgba(255,255,255,0.1)'; setFlipped(false); }} />
                </div>
              </div>
            )}

            {/* UPI */}
            {tab === 'upi' && (
              <div style={{ marginBottom: '1.2rem' }}>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginBottom: '1.2rem' }}>
                  {['GPay', 'PhonePe', 'Paytm', 'BHIM'].map(app => (
                    <button key={app} onClick={() => setUpi(app)} style={{ padding: '12px', background: upi === app ? 'rgba(212,175,55,0.1)' : '#111', border: `1px solid ${upi === app ? 'rgba(212,175,55,0.3)' : 'rgba(255,255,255,0.07)'}`, borderRadius: '10px', color: upi === app ? GOLD : '#666', cursor: 'pointer', fontFamily: T, fontWeight: 600, fontSize: '0.86rem', transition: 'all 0.2s' }}>
                      {app}
                    </button>
                  ))}
                </div>
                <label style={{ display: 'block', color: '#555', fontSize: '0.72rem', fontWeight: 700, letterSpacing: '0.5px', textTransform: 'uppercase', marginBottom: '6px' }}>Or enter UPI ID</label>
                <input value={typeof upi === 'string' && upi.includes('@') ? upi : ''} onChange={e => setUpi(e.target.value)} placeholder="yourname@upi" style={inp}
                  onFocus={e => e.target.style.borderColor = GOLD}
                  onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.1)'} />
              </div>
            )}

            {/* Net Banking */}
            {tab === 'netbanking' && (
              <div style={{ marginBottom: '1.2rem' }}>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '8px' }}>
                  {BANKS.map(b => (
                    <button key={b} onClick={() => setBank(b)} style={{ padding: '12px 8px', background: bank === b ? 'rgba(212,175,55,0.1)' : '#111', border: `1px solid ${bank === b ? 'rgba(212,175,55,0.3)' : 'rgba(255,255,255,0.07)'}`, borderRadius: '10px', color: bank === b ? GOLD : '#666', cursor: 'pointer', fontFamily: T, fontWeight: 600, fontSize: '0.82rem', transition: 'all 0.2s' }}>
                      {b}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <button onClick={pay} style={{ width: '100%', padding: '14px', background: GOLD, color: '#000', border: 'none', borderRadius: '10px', fontWeight: 700, fontSize: '0.95rem', cursor: 'pointer', fontFamily: T }}>
              Pay ₹{amount.toLocaleString()}
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default function MyBookings() {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [payingBooking, setPayingBooking] = useState(null);
  const [filter, setFilter] = useState('all');

  useEffect(() => { fetchBookings(); }, []);

  const fetchBookings = async () => {
    try {
      const res = await API.get('/bookings/my-bookings');
      setBookings(res.data?.bookings || res.data || []);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  const cancel = async (id) => {
    if (!window.confirm('Cancel this booking?')) return;
    try {
      await API.patch(`/bookings/${id}/cancel`);
      fetchBookings();
    } catch { alert('Failed to cancel.'); }
  };

  const filtered = filter === 'all' ? bookings : bookings.filter(b => b.status === filter);

  const STATUS_COLOR = {
    confirmed: { bg: 'rgba(48,209,88,0.1)', color: '#30D158', border: 'rgba(48,209,88,0.2)' },
    pending:   { bg: 'rgba(255,214,10,0.1)', color: '#FFD60A', border: 'rgba(255,214,10,0.2)' },
    cancelled: { bg: 'rgba(255,69,58,0.1)',  color: '#FF453A', border: 'rgba(255,69,58,0.2)' },
    booked:    { bg: 'rgba(48,209,88,0.1)',  color: '#30D158', border: 'rgba(48,209,88,0.2)' },
  };

  return (
    <div style={{ background: '#000', minHeight: '100vh', fontFamily: T, color: '#fff', padding: '2.5rem' }}>
      <style>{`@keyframes fadeUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}`}</style>

      {/* Header */}
      <div style={{ marginBottom: '2.5rem' }}>
        <p style={{ color: GOLD, fontSize: '0.72rem', fontWeight: 700, letterSpacing: '2px', textTransform: 'uppercase', margin: '0 0 6px' }}>Account</p>
        <h1 style={{ color: '#fff', fontWeight: 700, fontSize: '2rem', margin: 0, letterSpacing: '-1px' }}>My Bookings</h1>
      </div>

      {/* Filters */}
      <div style={{ display: 'flex', gap: '4px', marginBottom: '2rem', background: '#0d0d0d', borderRadius: '12px', padding: '4px', border: '1px solid rgba(255,255,255,0.06)', width: 'fit-content' }}>
        {['all', 'confirmed', 'pending', 'cancelled'].map(f => (
          <button key={f} onClick={() => setFilter(f)} style={{ padding: '8px 18px', borderRadius: '9px', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: '0.82rem', fontFamily: T, textTransform: 'capitalize', background: filter === f ? GOLD : 'transparent', color: filter === f ? '#000' : '#555', transition: 'all 0.2s' }}>
            {f}
          </button>
        ))}
      </div>

      {loading ? (
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '40vh' }}>
          <div style={{ width: '36px', height: '36px', border: '2px solid #222', borderTopColor: GOLD, borderRadius: '50%', animation: 'spin 0.8s linear infinite' }} />
          <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
        </div>
      ) : filtered.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '5rem', color: '#333' }}>
          <p style={{ fontSize: '2rem', marginBottom: '1rem' }}>◈</p>
          <p style={{ color: '#555', fontWeight: 600 }}>No bookings found</p>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', animation: 'fadeUp 0.4s ease' }}>
          {filtered.map((b, i) => {
            const sc = STATUS_COLOR[b.status] || STATUS_COLOR.pending;
            const amount = b.totalAmount || b.totalPrice || b.amount || 0;
            return (
              <div key={b._id || i} style={{ background: '#0d0d0d', border: '1px solid rgba(255,255,255,0.07)', borderRadius: '16px', padding: '1.4rem', display: 'flex', alignItems: 'center', gap: '1.5rem', flexWrap: 'wrap' }}>
                <div style={{ flex: 1, minWidth: '200px' }}>
                  <h3 style={{ color: '#fff', fontWeight: 700, fontSize: '0.97rem', margin: '0 0 6px' }}>{b.event?.name || b.eventName || 'Event'}</h3>
                  <div style={{ display: 'flex', gap: '1.5rem', flexWrap: 'wrap' }}>
                    {b.event?.date && <span style={{ color: '#555', fontSize: '0.8rem' }}>📅 {new Date(b.event.date).toLocaleDateString('en-IN')}</span>}
                    <span style={{ color: '#555', fontSize: '0.8rem' }}>🎫 {b.quantity || 1} ticket{(b.quantity || 1) > 1 ? 's' : ''}</span>
                    {amount > 0 && <span style={{ color: GOLD, fontSize: '0.82rem', fontWeight: 700 }}>₹{amount.toLocaleString()}</span>}
                  </div>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '10px', flexWrap: 'wrap' }}>
                  <span style={{ padding: '5px 12px', borderRadius: '20px', fontSize: '0.72rem', fontWeight: 700, background: sc.bg, color: sc.color, border: `1px solid ${sc.border}`, textTransform: 'uppercase' }}>{b.status}</span>
                  {(b.status === 'pending' || b.status === 'booked') && amount > 0 && (
                    <button onClick={() => setPayingBooking(b)} style={{ padding: '8px 18px', background: GOLD, color: '#000', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 700, fontSize: '0.82rem', fontFamily: T }}>Pay Now</button>
                  )}
                  {b.status !== 'cancelled' && (
                    <button onClick={() => cancel(b._id)} style={{ padding: '8px 16px', background: 'transparent', color: '#FF453A', border: '1px solid rgba(255,69,58,0.2)', borderRadius: '8px', cursor: 'pointer', fontWeight: 600, fontSize: '0.82rem', fontFamily: T, transition: 'background 0.2s' }}
                      onMouseEnter={e => e.currentTarget.style.background = 'rgba(255,69,58,0.08)'}
                      onMouseLeave={e => e.currentTarget.style.background = 'transparent'}>
                      Cancel
                    </button>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {payingBooking && (
        <PaymentModal
          booking={payingBooking}
          onClose={() => setPayingBooking(null)}
          onSuccess={fetchBookings}
        />
      )}
    </div>
  );
}
